class MyQueue:
    def __init__(self):
        self.stack1 = []
        self.stack2 = []

    def push(self, x):
        self.stack1.append(x)

    def pop(self):
        self.peek()
        return self.stack2.pop()

    def peek(self):
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())
        return self.stack2[-1]

    def empty(self):
        return not self.stack1 and not self.stack2

def runMyQueue(operations, values):
    obj = None
    results = []

    for i, op in enumerate(operations):
        if op == "MyQueue":
            obj = MyQueue()
            results.append(None)
        elif op == "push":
            obj.push(values[i][0])
            results.append(None)
        elif op == "pop":
            results.append(obj.pop())
        elif op == "peek":
            results.append(obj.peek())
        elif op == "empty":
            results.append(obj.empty())

    return results

